sql:
SELECT population AS total_population
  FROM union_territories
  WHERE name = 'Chandigarh';

external_knowledge:
Top three most populous cities implies the three highest populations in each union territory; 
Population is the number of people living in a city;
A union territory refers to an administrative division in a country, governed directly by the central government.

sql:
SELECT name
FROM union_territories
WHERE area_km2 > 500;

SELECT name, established_date
FROM union_territories
ORDER BY established_date ASC;

SELECT name
FROM union_territories
WHERE zone_id = (SELECT zone_id FROM zones WHERE name = 'Southern');

SELECT COUNT(*) AS ut_count
FROM union_territories
WHERE zone_id = (SELECT zone_id FROM zones WHERE name = 'Southern');

SELECT AVG(ut.population_density) AS average_population_density
FROM union_territories ut
WHERE ut.capital_city_id = ut.largest_city_id;

SELECT name
FROM union_territories
ORDER BY population DESC;

SELECT name, population
FROM union_territories
ORDER BY population DESC;

SELECT name
FROM union_territories
WHERE population_density = (
  SELECT MAX(population_density)
  FROM union_territories
);

SELECT name, population
FROM union_territories
WHERE ut_id = 1;
